Avg_P = 5;
BB_P = 20;
BB_D = 2;
Within_N =20;

// 1. 기본 정의
M5 = ma(C, Avg_P);
BB하단 = BBandsDown(BB_P, BB_D);

// 2. BB하단 이탈 발생 시점 체크
이탈발생 = L < BB하단;

// 3. 최근 N봉 이내에 BB하단 이탈이 있었는지 확인
최근이탈여부 = CountSince(date!=date(1), 이탈발생) > 0 or Highest(if(이탈발생,1,0), Within_N) > 0;

// 4. 5일선 저점(V자 반등) 정의
저점조건 = M5 > M5(1) && M5(1) < M5(2);

// 5. 쌍바닥 판단 (최근 두 개의 저점값 비교)
저점값1 = ValueWhen(1, 저점조건, M5(1));
저점값2 = ValueWhen(2, 저점조건, M5(1));

// 저점이 높아지는 우상향 쌍바닥 (신뢰도 높음)
쌍바닥 = 저점조건 && 저점값1 >= 저점값2;

// 6. 최종 조건
// BB이탈 이력이 있는 상태에서 + 쌍바닥이 나오고 + 5일선을 돌파할 때
최근이탈여부 && 쌍바닥 && CrossUp(C, M5)
